@code {
    // ── Navigation ──
    private string ActiveSection { get; set; } = "profile";

    private readonly record struct SectionDef(string Key, string Label, string Icon);
    private static readonly SectionDef[] _sections =
    [
        new("profile", "Profile", "👤"),
        new("notifications", "Notifications", "🔔"),
        new("security", "Security", "🔒"),
        new("appearance", "Appearance", "🎨"),
    ];

    // ── Shared state ──
    private bool _loading = true;
    private bool _saving;
    private string? _toastMessage;
    private bool _toastIsError;

    // ── Profile state ──
    private UserProfile? _savedProfile;
    private string _editDisplayName = "";
    private string _editEmail = "";
    private string _editAvatarUrl = "";
    private string _editBio = "";

    // ── Notification state ──
    private bool _editEmailNotif;
    private bool _editPushNotif;
    private bool _editWeeklyDigest;
    private HashSet<string> _editMutedChannels = new();
    private List<string> _allChannels = MockSettingsService.GetAllChannels();

    // ── Security state ──
    private SecuritySettings? _securitySettings;
    private bool _twoFactorEnabled;
    private bool _passwordPanelOpen;
    private string _currentPassword = "";
    private string _newPassword = "";
    private string _confirmPassword = "";
    private ActiveSession? _sessionToRevoke;

    // ── Appearance state ──
    private string _editTheme = "Light";
    private string _editFontSize = "Medium";
    private string _editLanguage = "English";
    private bool _editCompactMode;

    // ── Lifecycle ──

    protected override async Task OnInitializedAsync()
    {
        var profileTask = SettingsService.GetProfileAsync();
        var notifTask = SettingsService.GetNotificationPrefsAsync();
        var securityTask = SettingsService.GetSecuritySettingsAsync();
        var appearanceTask = SettingsService.GetAppearanceAsync();

        await Task.WhenAll(profileTask, notifTask, securityTask, appearanceTask);

        // Profile
        _savedProfile = profileTask.Result;
        ApplyProfileToEdit(_savedProfile);

        // Notifications
        var notif = notifTask.Result;
        _editEmailNotif = notif.EmailNotifications;
        _editPushNotif = notif.PushNotifications;
        _editWeeklyDigest = notif.WeeklyDigest;
        _editMutedChannels = new HashSet<string>(notif.MutedChannels);

        // Security
        _securitySettings = securityTask.Result;
        _twoFactorEnabled = _securitySettings.TwoFactorEnabled;

        // Appearance
        var appearance = appearanceTask.Result;
        _editTheme = appearance.Theme;
        _editFontSize = appearance.FontSize;
        _editLanguage = appearance.Language;
        _editCompactMode = appearance.CompactMode;

        _loading = false;
    }

    // ── Profile ──

    private void ApplyProfileToEdit(UserProfile p)
    {
        _editDisplayName = p.DisplayName;
        _editEmail = p.Email;
        _editAvatarUrl = p.AvatarUrl;
        _editBio = p.Bio;
    }

    private async Task SaveProfile()
    {
        _saving = true;
        var updated = new UserProfile(_editDisplayName, _editEmail, _editAvatarUrl, _editBio);
        await SettingsService.SaveProfileAsync(updated);
        _savedProfile = updated;
        _saving = false;
        ShowToast("Profile saved successfully.");
    }

    private void DiscardProfileChanges()
    {
        if (_savedProfile is not null)
        {
            ApplyProfileToEdit(_savedProfile);
        }
        ShowToast("Changes discarded.");
    }

    // ── Notifications ──

    private void ToggleMutedChannel(string channel, bool muted)
    {
        if (muted)
            _editMutedChannels.Add(channel);
        else
            _editMutedChannels.Remove(channel);
    }

    private async Task SaveNotifications()
    {
        _saving = true;
        var prefs = new NotificationPrefs(_editEmailNotif, _editPushNotif, _editWeeklyDigest, _editMutedChannels.ToList());
        await SettingsService.SaveNotificationPrefsAsync(prefs);
        _saving = false;
        ShowToast("Notification preferences saved.");
    }

    // ── Security ──

    private async Task ChangePassword()
    {
        if (string.IsNullOrWhiteSpace(_newPassword) || _newPassword != _confirmPassword)
        {
            ShowToast("Passwords do not match or are empty.", isError: true);
            return;
        }

        _saving = true;
        await SettingsService.ChangePasswordAsync(_currentPassword, _newPassword);
        _securitySettings = await SettingsService.GetSecuritySettingsAsync();
        _currentPassword = "";
        _newPassword = "";
        _confirmPassword = "";
        _saving = false;
        ShowToast("Password updated successfully.");
    }

    private void PromptRevokeSession(ActiveSession session) => _sessionToRevoke = session;
    private void CancelRevoke() => _sessionToRevoke = null;

    private async Task ConfirmRevokeSession()
    {
        if (_sessionToRevoke is null) return;
        _saving = true;
        await SettingsService.RevokeSessionAsync(_sessionToRevoke.Id);
        _securitySettings = await SettingsService.GetSecuritySettingsAsync();
        _sessionToRevoke = null;
        _saving = false;
        ShowToast("Session revoked.");
    }

    // ── Appearance ──

    private string GetPreviewClasses()
    {
        var classes = new List<string>();
        classes.Add(_editTheme switch { "Dark" => "preview-dark", "System" => "preview-system", _ => "preview-light" });
        classes.Add(_editFontSize switch { "Small" => "preview-font-sm", "Large" => "preview-font-lg", _ => "preview-font-md" });
        if (_editCompactMode) classes.Add("preview-compact");
        return string.Join(" ", classes);
    }

    private async Task SaveAppearance()
    {
        _saving = true;
        var settings = new AppearanceSettings(_editTheme, _editFontSize, _editLanguage, _editCompactMode);
        await SettingsService.SaveAppearanceAsync(settings);
        _saving = false;
        ShowToast("Appearance settings saved.");
    }

    // ── Toast helper ──

    private void ShowToast(string message, bool isError = false)
    {
        _toastMessage = message;
        _toastIsError = isError;
    }

    private void DismissToast() => _toastMessage = null;

    private static string FormatLastActive(DateTime dt)
    {
        var diff = DateTime.UtcNow - dt;
        if (diff.TotalMinutes < 60) return $"{(int)diff.TotalMinutes}m ago";
        if (diff.TotalHours < 24) return $"{(int)diff.TotalHours}h ago";
        return $"{(int)diff.TotalDays}d ago";
    }
}

