@page "/settings"
@rendermode InteractiveServer
@using sv_c90f1becb3f3453e9f0bbc604e5532ce.Services
@inject ISettingsService SettingsService

<PageTitle>Settings</PageTitle>

<div class="settings-layout">
    <!-- Left sidebar navigation -->
    <nav class="settings-sidebar">
        <h4 class="sidebar-title">Settings</h4>
        <ul class="nav flex-column">
            @foreach (var section in _sections)
            {
                <li class="nav-item">
                    <button class="nav-link @(ActiveSection == section.Key ? "active" : "")"
                            @onclick="() => ActiveSection = section.Key">
                        <span class="section-icon">@section.Icon</span>
                        @section.Label
                    </button>
                </li>
            }
        </ul>
    </nav>

    <!-- Main content area -->
    <main class="settings-content">
        @if (_loading)
        {
            <div class="text-center py-5">
                <div class="spinner-border" role="status">
                    <span class="visually-hidden">Loading...</span>
                </div>
            </div>
        }
        else
        {
            <!-- Toast / status message -->
            @if (!string.IsNullOrEmpty(_toastMessage))
            {
                <div class="alert @(_toastIsError ? "alert-danger" : "alert-success") alert-dismissible fade show" role="alert">
                    @_toastMessage
                    <button type="button" class="btn-close" @onclick="DismissToast"></button>
                </div>
            }

            @switch (ActiveSection)
            {
                case "profile":
                    @RenderProfile()
                    break;
                case "notifications":
                    @RenderNotifications()
                    break;
                case "security":
                    @RenderSecurity()
                    break;
                case "appearance":
                    @RenderAppearance()
                    break;
            }
        }
    </main>
</div>

@* ───── Profile Section ───── *@

@{
    RenderFragment RenderProfile() => __builder2 =>
    {
        <section>
            <h3>Profile</h3>
            <p class="text-muted">Manage your public profile information.</p>
            <hr />

            <div class="row g-4">
                <div class="col-md-8">
                    <div class="mb-3">
                        <label class="form-label">Display Name</label>
                        <input type="text" class="form-control" @bind="_editDisplayName" />
                    </div>
                    <div class="mb-3">
                        <label class="form-label">Email</label>
                        <input type="email" class="form-control" @bind="_editEmail" />
                    </div>
                    <div class="mb-3">
                        <label class="form-label">Bio</label>
                        <textarea class="form-control" rows="4" @bind="_editBio"></textarea>
                    </div>
                </div>
                <div class="col-md-4 text-center">
                    <label class="form-label">Avatar Preview</label>
                    <div class="avatar-preview mb-2">
                        <img src="@_editAvatarUrl" alt="Avatar" class="rounded-circle" width="120" height="120" />
                    </div>
                    <small class="text-muted text-break">@_editAvatarUrl</small>
                </div>
            </div>

            <div class="mt-4 d-flex gap-2">
                <button class="btn btn-primary" @onclick="SaveProfile" disabled="@_saving">
                    @if (_saving) { <span class="spinner-border spinner-border-sm me-1"></span> }
                    Save Changes
                </button>
                <button class="btn btn-outline-secondary" @onclick="DiscardProfileChanges">Discard Changes</button>
            </div>
        </section>
    };
}

@* ───── Notifications Section ───── *@

@{
    RenderFragment RenderNotifications() => __builder2 =>
    {
        <section>
            <h3>Notifications</h3>
            <p class="text-muted">Choose how you want to be notified.</p>
            <hr />

            <div class="mb-4">
                <div class="form-check form-switch mb-3">
                    <input class="form-check-input" type="checkbox" id="emailNotif" @bind="_editEmailNotif" />
                    <label class="form-check-label" for="emailNotif">Email Notifications</label>
                </div>
                <div class="form-check form-switch mb-3">
                    <input class="form-check-input" type="checkbox" id="pushNotif" @bind="_editPushNotif" />
                    <label class="form-check-label" for="pushNotif">Push Notifications</label>
                </div>
                <div class="form-check form-switch mb-3">
                    <input class="form-check-input" type="checkbox" id="weeklyDigest" @bind="_editWeeklyDigest" />
                    <label class="form-check-label" for="weeklyDigest">Weekly Digest</label>
                </div>
            </div>

            <h5>Muted Channels</h5>
            <p class="text-muted small">Check channels you want to mute.</p>
            <div class="row">
                @foreach (var channel in _allChannels)
                {
                    var ch = channel;
                    <div class="col-md-4 mb-2">
                        <div class="form-check">
                            <input class="form-check-input" type="checkbox" id="@($"ch-{ch}")"
                                   checked="@_editMutedChannels.Contains(ch)"
                                   @onchange="(e) => ToggleMutedChannel(ch, (bool)(e.Value ?? false))" />
                            <label class="form-check-label" for="@($"ch-{ch}")">@ch</label>
                        </div>
                    </div>
                }
            </div>

            <div class="mt-4">
                <button class="btn btn-primary" @onclick="SaveNotifications" disabled="@_saving">
                    @if (_saving) { <span class="spinner-border spinner-border-sm me-1"></span> }
                    Save Preferences
                </button>
            </div>
        </section>
    };
}

@* ───── Security Section ───── *@

@{
    RenderFragment RenderSecurity() => __builder2 =>
    {
        <section>
            <h3>Security</h3>
            <p class="text-muted">Manage your account security settings.</p>
            <hr />

            <!-- Change Password expandable panel -->
            <div class="card mb-4">
                <div class="card-header d-flex justify-content-between align-items-center"
                     style="cursor: pointer" @onclick="() => _passwordPanelOpen = !_passwordPanelOpen">
                    <strong>Change Password</strong>
                    <span>@(_passwordPanelOpen ? "▲" : "▼")</span>
                </div>
                @if (_passwordPanelOpen)
                {
                    <div class="card-body">
                        <div class="mb-3">
                            <label class="form-label">Current Password</label>
                            <input type="password" class="form-control" @bind="_currentPassword" />
                        </div>
                        <div class="mb-3">
                            <label class="form-label">New Password</label>
                            <input type="password" class="form-control" @bind="_newPassword" />
                        </div>
                        <div class="mb-3">
                            <label class="form-label">Confirm New Password</label>
                            <input type="password" class="form-control" @bind="_confirmPassword" />
                        </div>
                        <button class="btn btn-warning" @onclick="ChangePassword" disabled="@_saving">
                            @if (_saving) { <span class="spinner-border spinner-border-sm me-1"></span> }
                            Update Password
                        </button>
                        @if (_securitySettings?.LastPasswordChange is not null)
                        {
                            <small class="text-muted ms-3">
                                Last changed: @_securitySettings.LastPasswordChange.Value.ToString("MMM dd, yyyy")
                            </small>
                        }
                    </div>
                }
            </div>

            <!-- Two-factor authentication -->
            <div class="card mb-4">
                <div class="card-body d-flex justify-content-between align-items-center">
                    <div>
                        <strong>Two-Factor Authentication</strong>
                        <span class="badge @(_twoFactorEnabled ? "bg-success" : "bg-secondary") ms-2">
                            @(_twoFactorEnabled ? "Enabled" : "Disabled")
                        </span>
                    </div>
                    <div class="form-check form-switch mb-0">
                        <input class="form-check-input" type="checkbox" @bind="_twoFactorEnabled" />
                    </div>
                </div>
            </div>

            <!-- Active Sessions -->
            <h5>Active Sessions</h5>
            @if (_securitySettings?.Sessions.Count > 0)
            {
                <div class="table-responsive">
                    <table class="table table-hover">
                        <thead>
                            <tr>
                                <th>Device</th>
                                <th>Location</th>
                                <th>Last Active</th>
                                <th></th>
                            </tr>
                        </thead>
                        <tbody>
                            @foreach (var session in _securitySettings.Sessions)
                            {
                                <tr>
                                    <td>@session.Device</td>
                                    <td>@session.Location</td>
                                    <td>@FormatLastActive(session.LastActive)</td>
                                    <td>
                                        @if (session.Id != _securitySettings.Sessions[0].Id)
                                        {
                                            <button class="btn btn-sm btn-outline-danger"
                                                    @onclick="() => PromptRevokeSession(session)">
                                                Revoke
                                            </button>
                                        }
                                        else
                                        {
                                            <span class="badge bg-info">Current</span>
                                        }
                                    </td>
                                </tr>
                            }
                        </tbody>
                    </table>
                </div>
            }

            <!-- Revoke confirmation dialog -->
            @if (_sessionToRevoke is not null)
            {
                <div class="modal-backdrop fade show"></div>
                <div class="modal fade show d-block" tabindex="-1">
                    <div class="modal-dialog modal-dialog-centered">
                        <div class="modal-content">
                            <div class="modal-header">
                                <h5 class="modal-title">Revoke Session</h5>
                                <button type="button" class="btn-close" @onclick="CancelRevoke"></button>
                            </div>
                            <div class="modal-body">
                                <p>Are you sure you want to revoke the session on <strong>@_sessionToRevoke.Device</strong> from <strong>@_sessionToRevoke.Location</strong>?</p>
                                <p class="text-muted small">This will sign that device out immediately.</p>
                            </div>
                            <div class="modal-footer">
                                <button class="btn btn-secondary" @onclick="CancelRevoke">Cancel</button>
                                <button class="btn btn-danger" @onclick="ConfirmRevokeSession" disabled="@_saving">
                                    @if (_saving) { <span class="spinner-border spinner-border-sm me-1"></span> }
                                    Revoke
                                </button>
                            </div>
                        </div>
                    </div>
                </div>
            }
        </section>
    };
}

@* ───── Appearance Section ───── *@

@{
    RenderFragment RenderAppearance() => __builder2 =>
    {
        <section>
            <h3>Appearance</h3>
            <p class="text-muted">Customize how the application looks.</p>
            <hr />

            <div class="row g-4">
                <div class="col-md-6">
                    <!-- Theme -->
                    <div class="mb-4">
                        <label class="form-label fw-bold">Theme</label>
                        @foreach (var theme in new[] { "Light", "Dark", "System" })
                        {
                            <div class="form-check">
                                <input class="form-check-input" type="radio" name="theme"
                                       id="@($"theme-{theme}")" value="@theme"
                                       checked="@(_editTheme == theme)"
                                       @onchange="() => _editTheme = theme" />
                                <label class="form-check-label" for="@($"theme-{theme}")">@theme</label>
                            </div>
                        }
                    </div>

                    <!-- Font Size -->
                    <div class="mb-4">
                        <label class="form-label fw-bold">Font Size</label>
                        @foreach (var size in new[] { "Small", "Medium", "Large" })
                        {
                            <div class="form-check">
                                <input class="form-check-input" type="radio" name="fontSize"
                                       id="@($"fs-{size}")" value="@size"
                                       checked="@(_editFontSize == size)"
                                       @onchange="() => _editFontSize = size" />
                                <label class="form-check-label" for="@($"fs-{size}")">@size</label>
                            </div>
                        }
                    </div>

                    <!-- Language -->
                    <div class="mb-4">
                        <label class="form-label fw-bold" for="language">Language</label>
                        <select class="form-select" id="language" @bind="_editLanguage">
                            <option value="English">English</option>
                            <option value="Spanish">Spanish</option>
                            <option value="French">French</option>
                            <option value="German">German</option>
                            <option value="Japanese">Japanese</option>
                            <option value="Chinese">Chinese</option>
                        </select>
                    </div>

                    <!-- Compact Mode -->
                    <div class="mb-4">
                        <div class="form-check form-switch">
                            <input class="form-check-input" type="checkbox" id="compactMode" @bind="_editCompactMode" />
                            <label class="form-check-label" for="compactMode">Compact Mode</label>
                        </div>
                    </div>
                </div>

                <!-- Live preview -->
                <div class="col-md-6">
                    <label class="form-label fw-bold">Live Preview</label>
                    <div class="appearance-preview @GetPreviewClasses()">
                        <div class="preview-header">
                            <span class="fw-bold">App Header</span>
                            <span class="badge bg-primary">Badge</span>
                        </div>
                        <div class="preview-body">
                            <p>This is a preview of your selected appearance settings.</p>
                            <p class="text-muted">Theme: @_editTheme · Font: @_editFontSize · Lang: @_editLanguage</p>
                            <button class="btn btn-sm btn-primary">Sample Button</button>
                            <button class="btn btn-sm btn-outline-secondary ms-1">Cancel</button>
                        </div>
                    </div>
                </div>
            </div>

            <div class="mt-4">
                <button class="btn btn-primary" @onclick="SaveAppearance" disabled="@_saving">
                    @if (_saving) { <span class="spinner-border spinner-border-sm me-1"></span> }
                    Save
                </button>
            </div>
        </section>
    };
}

@code {
    // ── Navigation ──
    private string ActiveSection { get; set; } = "profile";

    private readonly record struct SectionDef(string Key, string Label, string Icon);
    private static readonly SectionDef[] _sections =
    [
        new("profile", "Profile", "👤"),
        new("notifications", "Notifications", "🔔"),
        new("security", "Security", "🔒"),
        new("appearance", "Appearance", "🎨"),
    ];

    // ── Shared state ──
    private bool _loading = true;
    private bool _saving;
    private string? _toastMessage;
    private bool _toastIsError;

    // ── Profile state ──
    private UserProfile? _savedProfile;
    private string _editDisplayName = "";
    private string _editEmail = "";
    private string _editAvatarUrl = "";
    private string _editBio = "";

    // ── Notification state ──
    private bool _editEmailNotif;
    private bool _editPushNotif;
    private bool _editWeeklyDigest;
    private HashSet<string> _editMutedChannels = new();
    private List<string> _allChannels = MockSettingsService.GetAllChannels();

    // ── Security state ──
    private SecuritySettings? _securitySettings;
    private bool _twoFactorEnabled;
    private bool _passwordPanelOpen;
    private string _currentPassword = "";
    private string _newPassword = "";
    private string _confirmPassword = "";
    private ActiveSession? _sessionToRevoke;

    // ── Appearance state ──
    private string _editTheme = "Light";
    private string _editFontSize = "Medium";
    private string _editLanguage = "English";
    private bool _editCompactMode;

    // ── Lifecycle ──

    protected override async Task OnInitializedAsync()
    {
        var profileTask = SettingsService.GetProfileAsync();
        var notifTask = SettingsService.GetNotificationPrefsAsync();
        var securityTask = SettingsService.GetSecuritySettingsAsync();
        var appearanceTask = SettingsService.GetAppearanceAsync();

        await Task.WhenAll(profileTask, notifTask, securityTask, appearanceTask);

        // Profile
        _savedProfile = profileTask.Result;
        ApplyProfileToEdit(_savedProfile);

        // Notifications
        var notif = notifTask.Result;
        _editEmailNotif = notif.EmailNotifications;
        _editPushNotif = notif.PushNotifications;
        _editWeeklyDigest = notif.WeeklyDigest;
        _editMutedChannels = new HashSet<string>(notif.MutedChannels);

        // Security
        _securitySettings = securityTask.Result;
        _twoFactorEnabled = _securitySettings.TwoFactorEnabled;

        // Appearance
        var appearance = appearanceTask.Result;
        _editTheme = appearance.Theme;
        _editFontSize = appearance.FontSize;
        _editLanguage = appearance.Language;
        _editCompactMode = appearance.CompactMode;

        _loading = false;
    }

    // ── Profile ──

    private void ApplyProfileToEdit(UserProfile p)
    {
        _editDisplayName = p.DisplayName;
        _editEmail = p.Email;
        _editAvatarUrl = p.AvatarUrl;
        _editBio = p.Bio;
    }

    private async Task SaveProfile()
    {
        _saving = true;
        var updated = new UserProfile(_editDisplayName, _editEmail, _editAvatarUrl, _editBio);
        await SettingsService.SaveProfileAsync(updated);
        _savedProfile = updated;
        _saving = false;
        ShowToast("Profile saved successfully.");
    }

    private void DiscardProfileChanges()
    {
        if (_savedProfile is not null)
        {
            ApplyProfileToEdit(_savedProfile);
        }
        ShowToast("Changes discarded.");
    }

    // ── Notifications ──

    private void ToggleMutedChannel(string channel, bool muted)
    {
        if (muted)
            _editMutedChannels.Add(channel);
        else
            _editMutedChannels.Remove(channel);
    }

    private async Task SaveNotifications()
    {
        _saving = true;
        var prefs = new NotificationPrefs(_editEmailNotif, _editPushNotif, _editWeeklyDigest, _editMutedChannels.ToList());
        await SettingsService.SaveNotificationPrefsAsync(prefs);
        _saving = false;
        ShowToast("Notification preferences saved.");
    }

    // ── Security ──

    private async Task ChangePassword()
    {
        if (string.IsNullOrWhiteSpace(_newPassword) || _newPassword != _confirmPassword)
        {
            ShowToast("Passwords do not match or are empty.", isError: true);
            return;
        }

        _saving = true;
        await SettingsService.ChangePasswordAsync(_currentPassword, _newPassword);
        _securitySettings = await SettingsService.GetSecuritySettingsAsync();
        _currentPassword = "";
        _newPassword = "";
        _confirmPassword = "";
        _saving = false;
        ShowToast("Password updated successfully.");
    }

    private void PromptRevokeSession(ActiveSession session) => _sessionToRevoke = session;
    private void CancelRevoke() => _sessionToRevoke = null;

    private async Task ConfirmRevokeSession()
    {
        if (_sessionToRevoke is null) return;
        _saving = true;
        await SettingsService.RevokeSessionAsync(_sessionToRevoke.Id);
        _securitySettings = await SettingsService.GetSecuritySettingsAsync();
        _sessionToRevoke = null;
        _saving = false;
        ShowToast("Session revoked.");
    }

    // ── Appearance ──

    private string GetPreviewClasses()
    {
        var classes = new List<string>();
        classes.Add(_editTheme switch { "Dark" => "preview-dark", "System" => "preview-system", _ => "preview-light" });
        classes.Add(_editFontSize switch { "Small" => "preview-font-sm", "Large" => "preview-font-lg", _ => "preview-font-md" });
        if (_editCompactMode) classes.Add("preview-compact");
        return string.Join(" ", classes);
    }

    private async Task SaveAppearance()
    {
        _saving = true;
        var settings = new AppearanceSettings(_editTheme, _editFontSize, _editLanguage, _editCompactMode);
        await SettingsService.SaveAppearanceAsync(settings);
        _saving = false;
        ShowToast("Appearance settings saved.");
    }

    // ── Toast helper ──

    private void ShowToast(string message, bool isError = false)
    {
        _toastMessage = message;
        _toastIsError = isError;
    }

    private void DismissToast() => _toastMessage = null;

    private static string FormatLastActive(DateTime dt)
    {
        var diff = DateTime.UtcNow - dt;
        if (diff.TotalMinutes < 60) return $"{(int)diff.TotalMinutes}m ago";
        if (diff.TotalHours < 24) return $"{(int)diff.TotalHours}h ago";
        return $"{(int)diff.TotalDays}d ago";
    }
}
